import os
import secrets
import json
from functools import wraps

import requests
from flask import Flask, redirect, request, session, url_for, jsonify, abort
from jose import jwt, JWTError


app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

# OIDC Configuration - set these via environment variables
OIDC_ISSUER = os.environ.get("OIDC_ISSUER", "https://your-idp.example.com")
OIDC_CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "your-client-id")
OIDC_CLIENT_SECRET = os.environ.get("OIDC_CLIENT_SECRET", "your-client-secret")
OIDC_REDIRECT_URI = os.environ.get("OIDC_REDIRECT_URI", "http://localhost:5000/callback")
OIDC_SCOPES = "openid email profile"

# Cache for OIDC discovery and JWKS
_oidc_config_cache = {}
_jwks_cache = {}


def get_oidc_discovery():
    """Fetch and cache the OIDC discovery document."""
    if not _oidc_config_cache:
        discovery_url = f"{OIDC_ISSUER.rstrip('/')}/.well-known/openid-configuration"
        resp = requests.get(discovery_url, timeout=10)
        resp.raise_for_status()
        _oidc_config_cache.update(resp.json())
    return _oidc_config_cache


def get_jwks():
    """Fetch and cache the JWKS (JSON Web Key Set) for token verification."""
    if not _jwks_cache:
        oidc_config = get_oidc_discovery()
        jwks_uri = oidc_config["jwks_uri"]
        resp = requests.get(jwks_uri, timeout=10)
        resp.raise_for_status()
        _jwks_cache.update(resp.json())
    return _jwks_cache


def verify_id_token(id_token, expected_nonce):
    """
    Verify the ID token signature, claims, and nonce.
    The nonce check prevents token replay attacks.
    """
    jwks = get_jwks()
    oidc_config = get_oidc_discovery()

    # Decode header to find the correct key
    unverified_header = jwt.get_unverified_header(id_token)
    kid = unverified_header.get("kid")

    # Find the matching key in JWKS
    rsa_key = None
    for key in jwks.get("keys", []):
        if key.get("kid") == kid:
            rsa_key = key
            break

    if rsa_key is None:
        raise JWTError("Unable to find matching key in JWKS")

    # Verify and decode the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=["RS256"],
        audience=OIDC_CLIENT_ID,
        issuer=oidc_config["issuer"],
        options={"require_sub": True},
    )

    # CRITICAL: Verify the nonce to prevent replay attacks
    # This ensures the token was issued in response to OUR authentication request
    token_nonce = claims.get("nonce")
    if token_nonce != expected_nonce:
        raise JWTError(
            "Nonce mismatch - possible token replay attack. "
            f"Expected: {expected_nonce}, Got: {token_nonce}"
        )

    return claims


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


